1	// Instantiates i2c_prog and i2c_bit,
2	// multiplexes access to a dpram
3	module i2c_chunk(
4		// Single clock domain, slave to the local bus
5		// hard-coded read/write 4K address space,
6		// subdivided into quarters as shown below
7		input clk,  // Rising edge clock input; all logic is synchronous in this domain
8		input [11:0] lb_addr,  // Local bus address
9		input [7:0] lb_din,  // Data from local bus master
10		input lb_write,  // memory space only
11		output [7:0] lb_dout,  // Data made available to local bus master
12		// Auxiliary control and status
13		input run_cmd,  // Command sequencer to run
14		input trace_cmd,  // Command analyzer to run
15		input freeze,  // Keep output buffer from changing
16		output run_stat,  // Reports if sequencer is running
17		output analyze_armed,
18		output analyze_run,  // reports if logic analyzer is tracing
19		output updated,  // New data is available in output buffer
20		output err_flag,  // Error condition detected
21		output [3:0] hw_config,  // Can be used to select between I2C busses
22		// Hardware pins: TWI (almost I2C) bus
23		output scl,  // Direct drive of SCL pin
24		output sda_drive,  // Low value should operate pull-down of SDA pin
25		input  sda_sense,  // SDA pin
26		input  scl_sense,  // SCL pin
27		input  trig_mode,  // 0 = internal (ta op code), 1 = external (pins)
28		input  rst,  // not yet used
29		input  intp  // not yet used
30	);
31	
32	parameter initial_file = "";
33	parameter tick_scale = 6;
34	// transparently passed to i2c_prog
35	parameter q1 = 2;  // o_p1 ticks are 2^(q1+1) * bit_adv
36	parameter q2 = 7;  // o_p2 ticks are 2^(q2+1) * bit_adv
37	
38	// Minor comment on the "freeze" input.  It's OK to play fast
39	// and loose with its clock domain, and even ignore it for a
40	// few cycles.  As long as it takes effect before a following
41	// read returns data, the sequence of reads that follows will
42	// stay self-consistent.  If the von Neumann machine that creates
43	// this command wants to be super-conservative, it's free to insert
44	// a bus cycle of some kind between the freeze command and the
45	// subsequent data read.
46	
47	// Goal for tick is 5.6 MHz or slightly slower; i2c_bit builds in
48	// divide-by-14, and 5.6 MHz / 14 = 400 kHz bit rate.
49	// 125 MHz / 32 = 3.9 MHz yields 280 kHz bit rate.
50	reg tick=0;
51	reg [tick_scale-1:0] access=0;
52	always @(posedge clk) begin
53		access <= access+1;
54		tick <= &access;
55	end
56	
57	// Main instantiation of programmable engine
58	wire bit_adv, sda_h;
59	wire [1:0] bit_cmd;
60	wire [9:0] p_addr;
61	reg  [7:0] p_data=0;
62	wire [7:0] result;
63	wire result_stb;
64	wire [9:0] result_p;
65	wire buffer_flip, trig_analyz;  // from i2c_prog
66	i2c_prog #(.q1(q1), .q2(q2)) prog (.clk(clk),
67		.bit_cmd(bit_cmd), .bit_adv(bit_adv), .sda_h(sda_h),
68		.p_addr(p_addr), .p_data(p_data),
69		.result(result), .result_stb(result_stb), .result_addr(result_p),
70		.run_cmd(run_cmd), .run_stat(run_stat), .hw_config(hw_config),
71		.buffer_flip(buffer_flip), .trig_analyz(trig_analyz)
72	);
73	
74	// That engine delegates pin driving to i2c_bit
75	wire scl_o;
76	i2c_bit ibit (.clk(clk),
77		.tick(tick), .advance(bit_adv),
78		.command(bit_cmd),
79		.scl_o(scl_o), .sda_o(sda_drive), .sda_v(sda_sense), .sda_h(sda_h)
80	);
81	
82	// Then i2c_analyze observes the pin levels
83	wire [7:0] trace;
84	wire trace_push, ext_trig;
85	reg trace_run=0;
86	i2c_analyze analyze(.clk(clk), .tick(tick),
87		.scl(scl_sense), .sda(sda_sense), .intp(intp), .rst(rst),
88		.bit_adv(bit_adv), .bit_cmd(bit_cmd), .trig_out(ext_trig),
89		.trace(trace), .trace_push(trace_push), .run(trace_run)
90	);
91	
92	reg [9:0] trace_a=0;  // Trace buffer counter, might be OK to stay here
93	reg [7:0] trace_h=0;  // analyze module doesn't buffer this
94	reg trace_k=0, trace_armed=0, trace_cmd_d=0;
95	wire trigger = trig_mode ? ext_trig : trig_analyz;
96	wire trace_done = &trace_a;
97	always @(posedge clk) begin
98		trace_cmd_d <= trace_cmd;
99		if (trace_cmd & ~trace_cmd_d & ~trace_run) trace_armed <= 1;
100		if (trace_armed & trigger) begin
101			trace_run <= 1;
102			trace_armed <= 0;
103		end
104		if (trace_done) trace_run <= 0;
105	end
106	assign analyze_run = trace_run;
107	assign analyze_armed = trace_armed;
108	
109	// Logic governing ping-pong result buffer
110	// Updated flag can be read along with data during a freeze
111	reg pingpong=0, freeze_r=0, freeze_d=0, updated_r=0;
112	always @(posedge clk) begin
113		freeze_r <= freeze;  // Just in case freeze comes from another domain
114		freeze_d <= freeze_r;
115		if (buffer_flip & ~freeze_d) begin
116			pingpong <= ~pingpong;
117			updated_r <= 1;
118		end
119		if (~freeze_r & freeze_d) updated_r <= 0;
120	end
121	
122	// no need for a data buffer, result is static for many cycles
123	reg result_k=0;
124	
125	// Collate write requests
126	// Output is the "X-bus" signals xbd (data), xba(address), and xbs (strobe)
127	// Memory is subdivided into quarters:
128	//   0x000 - 0x3ff   program
129	//   0x400 - 0x7ff   logic analyzer
130	//   0x800 - 0xbff   results
131	//   0xc00 - 0xfff   result buffer in progress (not meant for host access)
132	// The local bus side can read and write all of it.
133	reg [7:0] lb_wbufd=0, xbd=0;
134	reg [11:0] lb_wbufa=0, xba=0;
135	reg lb_wpend=0, err=0, xbs=0;
136	wire [7:0] xbo;  // local read data
137	wire [11:0] result_addr = {1'b1, pingpong, result_p};
138	always @(posedge clk) begin
139		// Write bus multiplex
140		casez (access[3:0])
141			4'b???0: begin xbd <= lb_wbufd; xba <= lb_wbufa; xbs <= lb_wpend; lb_wpend <= 0; end
142			4'b0001: begin xbd <= trace_h;  xba <= {2'd1, trace_a};  xbs <= trace_k; trace_k <= 0;  if (trace_k) trace_a <= trace_a+1; end
143			4'b0011: begin xbd <= result;   xba <= result_addr; xbs <= result_k; result_k <= 0; end
144			4'b0101: begin xbd <= 8'bx;     xba <= {2'd0, p_addr};   xbs <= 0; end
145			default: begin xbd <= 8'bx;     xba <= 12'bx; xbs <= 0; end
146		endcase
147		if (access[3:0]==7) p_data <= xbo;  // two cycles after p_addr presented on xba
148		// Capture write cycles
149		if (lb_write) begin
150			lb_wbufd <= lb_din;
151			lb_wbufa <= lb_addr;
152			lb_wpend <= 1;
153			if (lb_wpend) err <= 1;
154		end
155		// Capture results
156		if (result_stb) result_k <= 1;
157		// Capture trace events
158		if (trace_push) begin
159			trace_h <= trace;
160			trace_k <= 1;
161		end
162		// Close out a finished trace
163		if (~trace_run) trace_a <= 0;
164	end
165	
166	// Special attention to support atomic buffer flip
167	wire lb_flip = lb_addr[11] & ~pingpong;
168	wire [11:0] lb_addr1 = lb_addr ^ {1'b0, lb_flip, 10'b0};
169	
170	wire [7:0] lb_dout0;
171	dpram #(.aw(12), .dw(8),
172		.initial_file(initial_file)) dpram(
173		.clka(clk), .addra(xba), .dina(xbd), .wena(xbs), .douta(xbo),
174		.clkb(clk), .addrb(lb_addr1), .doutb(lb_dout0)
175	);
176	assign lb_dout = lb_dout0;
177	
178	// Eric Norum suggests true active drive for SCL, since it's edge sensitive
179	assign scl = scl_o;
180	assign err_flag = err;
181	assign updated = updated_r;
182	
183	endmodule
