1	module i2c_prog(
2		input clk,
3		// attachment to i2c_bit
4		output [1:0] bit_cmd,
5		input bit_adv,
6		input sda_h,
7		// attachment to program memory
8		output [9:0] p_addr,
9		input [7:0] p_data,
10		// Result port
11		output [7:0] result,
12		output [9:0] result_addr,
13		output result_stb,
14		// other control and status
15		input run_cmd,
16		output run_stat,
17		output [3:0] hw_config,
18		output buffer_flip,
19		output trig_analyz
20	);
21	
22	parameter q1 = 2;  // o_p1 ticks are 2^(q1+1) * bit_adv
23	parameter q2 = 7;  // o_p2 ticks are 2^(q2+1) * bit_adv
24	
25	// Most fundamental state bit: are we running or not?
26	reg run_stat_r=0, run_cmd_d1=0, run_cmd_d2=0;
27	wire start_me_up = run_cmd_d1 & ~run_cmd_d2;
28	wire ok_to_stop, natural_stop;  // defined later
29	wire stop_now = ~run_cmd_d1 & ok_to_stop | natural_stop;
30	always @(posedge clk) if (bit_adv) begin
31		run_cmd_d1 <= run_cmd;  // remove all doubt about clock domains
32		run_cmd_d2 <= run_cmd_d1;
33		if (start_me_up) run_stat_r <= 1;
34		if (stop_now) run_stat_r <= 0;
35	end
36	assign run_stat = run_stat_r;
37	
38	// State variable
39	reg [2:0] state=0;
40	localparam s_idle  = 0;
41	localparam s_start = 1;  // start bit for data transfer instructions, idle for others
42	localparam s_data  = 2;
43	localparam s_ack   = 3;
44	localparam s_pad   = 4;
45	localparam s_stop  = 5;
46	
47	// Opcode and encoding
48	reg [2:0] opcode=0;
49	reg [4:0] stream_cnt=0;
50	wire o_oo = opcode==0;  // special functions, including sleep
51	wire o_rd = opcode==1;  // read
52	wire o_wr = opcode==2;  // write
53	wire o_wx = opcode==3;  // write followed by repeated start
54	wire o_p1 = opcode==4;  // pause (time quantum 1)
55	wire o_p2 = opcode==5;  // pause (time quantum 2)
56	wire o_jp = opcode==6;  // jump
57	wire o_sx = opcode==7;  // set result address
58	
59	wire op_r = opcode==1;
60	wire op_w = ~opcode[2] & opcode[1];
61	wire op_xf = o_rd | o_wr | o_wx;
62	wire op_pw = o_p1 | o_p2;  // any pause command
63	wire op_zz = o_oo & (stream_cnt==0);  // sleep
64	wire op_bf = o_oo & (stream_cnt==2);  // buffer flip
65	wire op_ta = o_oo & (stream_cnt==3);  // trigger logic analyzer
66	wire op_hw = o_oo & (stream_cnt[4]);  // hardware config
67	wire op_ia = op_pw | o_jp | op_zz;  // any interrupt-able command
68	
69	// Base state machine
70	wire bit_end, stream_end;
71	always @(posedge clk) if (bit_adv) case(state)
72		s_idle:  if (start_me_up) state <= s_start;
73		s_start: state <= stop_now ? s_idle : op_xf ? s_data : s_start;
74		s_data:  if (bit_end) state <= s_ack;
75		s_ack:   state <= s_pad;
76		s_pad:   if (stream_end) state <= o_wx ? s_start : s_stop; else state <= s_data;
77		s_stop:  state <= s_start;
78	endcase
79	//
80	assign ok_to_stop = op_ia & (state==s_start);
81	//assign natural_stop = op_zz & (state==s_idle);
82	//assign natural_stop = op_zz & next_op;
83	assign natural_stop = op_zz;
84	
85	
86	// Manipulate secondary state, notably bit_cnt, opcode, and stream_cnt
87	reg [2:0] bit_cnt=0;
88	assign bit_end = bit_cnt == 0;
89	assign stream_end = stream_cnt == 0;
90	reg stream0=0, stream1=0;
91	wire rd_cycle = o_rd & ~stream1;
92	wire wr_cycle = op_w | (o_rd & stream1);  // during data transfers
93	wire wr_cycle0 = op_w | (o_rd & stream0);  // during initial start pulse
94	reg [9:0] pc=0;  // program counter
95	reg [7:0] sr=0;  // data shift register
96	wire next_data =
97		((state==s_start) & op_xf) |
98		((state==s_pad) & ~stream_end);
99	wire next_op =
100		((state==s_pad) &  stream_end & o_wx) |
101		((state==s_stop)) |
102		((state==s_idle)) |
103		((state==s_start) & op_pw & stream_end) |
104		((state==s_start) & o_jp) |
105		((state==s_start) & o_sx) |
106		((state==s_start) & op_bf) |
107		((state==s_start) & op_ta) |
108		((state==s_start) & op_hw);
109	wire [7:0] next_sr = (sr << 1) | sda_h;
110	reg [7:0] pause_cnt=0;
111	reg [9:0] next_pc=0;
112	reg pause1_tick=0, pause2_tick=0;
113	always @(posedge clk) if (bit_adv) begin
114		pause_cnt <= pause_cnt+1;  // free-running
115		pause1_tick <= &pause_cnt[q1:0];
116		pause2_tick <= &pause_cnt[q2:0];
117		if (next_data) begin
118			bit_cnt <= 7;
119			stream_cnt <= stream_cnt - 1;
120			stream0 <= 0;
121			stream1 <= stream0;
122			if (wr_cycle0) begin
123				sr <= p_data;
124				pc <= next_pc;
125			end
126		end
127		//if ((state==s_data) & ~bit_end) begin
128		if (state==s_data) begin
129			sr <= next_sr;
130			bit_cnt <= bit_cnt - 1;
131		end
132		if (o_p1 & pause1_tick | o_p2 & pause2_tick) begin
133			stream_cnt <= stream_cnt - 1;
134		end
135		if (next_op) begin
136			opcode <= p_data[7:5];
137			stream_cnt <= p_data[4:0];
138			stream0 <= 1;
139			stream1 <= 0;
140			pc <= next_pc;
141		end
142	end
143	
144	// Special cases
145	reg [9:0] result_addr_r=0;
146	reg [3:0] hw_config_r=0;
147	reg result_incr_pend=0;
148	wire result_incr_sel = (state==s_ack) & rd_cycle;
149	always @(posedge clk) begin
150		next_pc <= ~run_stat_r ? 10'b0 : o_jp ? {stream_cnt, 5'b0} : pc + 1;
151		if (bit_adv) result_incr_pend <= result_incr_sel;
152		if (bit_adv & result_incr_pend) result_addr_r <= result_addr + 1;
153		if (bit_adv & o_sx) result_addr_r <= {stream_cnt, 5'b0};
154		if (bit_adv & op_hw) hw_config_r <= stream_cnt[3:0];
155	end
156	
157	// Decoder; see i2c_bit.v
158	//  bit_cmd semantics    0: Tx0   1: Tx1   2: L   3: H
159	wire data_bit = rd_cycle ? 1'b1 : sr[7];
160	wire ack_bit = rd_cycle ? stream_end : 1'b1;
161	wire [1:0] pad_wr = stream_end ? 2'b00 : 2'b11;
162	wire [1:0] pad_wx = stream_end ? 2'b01 : 2'b11;
163	wire [1:0] pad_rd = stream_end ? 2'b00 : 2'b10;
164	reg [1:0] bc;
165	always @(posedge clk) case(state)
166		s_idle:  bc <= 2'b11;  // H
167		s_start: bc <= op_xf ? 2'b10 : 2'b11;  // L or H
168		s_data:  bc <= {1'b0, data_bit};
169		s_ack:   bc <= {1'b0, ack_bit};
170		s_pad:   bc <= o_rd ? pad_rd : o_wx ? pad_wx : pad_wr;
171		s_stop:  bc <= 2'b11;  // H
172	endcase
173	
174	assign p_addr = next_pc;
175	assign bit_cmd = bc;
176	assign result_stb = bit_adv & result_incr_sel;
177	assign result = next_sr;  // result_stb ? next_sr : 8'bx;
178	assign result_addr = result_addr_r;
179	assign buffer_flip = op_bf & bit_adv;
180	assign trig_analyz = op_ta & bit_adv;
181	assign hw_config = hw_config_r;
182	
183	// Future additions?
184	//  Raw send (4)
185	//  Skip on interrupt
186	//  PDP-5 opcodes?
187	//    000  and  Logical AND
188	//    001  tad  Twos complement add
189	//    010  isz  Index and skip if zero
190	//    011  dca  Deposit and clear accumulator
191	//    100  jms  Jump to subroutine
192	//    101  jmp  Jump
193	//    110  iot  Input/output transfer
194	//    111  opr  Operate: rotate, clear, increment, conditional skip, halt
195	
196	endmodule
